joi_block.script:
t1 = all(#TemperatureSensor #WineCellar).temperatureSensor_temperature
delay(10 MIN)
t2 = all(#TemperatureSensor #WineCellar).temperatureSensor_temperature
diff = t2 - t1
if (diff < 0) {
diff = t1 - t2
}
if (diff >= 1) {
(#Speaker).speaker_speak("The wine cellar temperature has changed rapidly")
}

